#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
bool vis[105][105];CI dx[]={-2,-1,1,2,2,2,2,1,-1,-2,2,-2},dy[]={2,2,2,2,1,-1,-2,-2,-2,-2,1,-1};int X,Y;
struct Node{int x,y,step;}q[1100];
void bfs(int X,int Y){
	int head=0,tail=1,nx,ny;q[1].x=X,q[1].y=Y,q[1].step=0;vis[X][Y]=true;
	while(head++<tail)
		for(int i=0;i<12;++i){
			nx=q[head].x+dx[i],ny=q[head].y+dy[i];
			if((nx>=1&&nx<101)&&(ny>=1&&ny<101)&&vis[nx][ny]==false){
			    q[++tail].x=nx;q[tail].y=ny,q[tail].step=q[head].step+1,vis[nx][ny]=true;
				if(nx==1&&ny==1){printf("%d\n",q[tail].step);return;}
			}
		}return;
}
int main(void){scanf("%d%d",&X,&Y);bfs(X,Y);memset(vis,false,sizeof(vis));scanf("%d%d",&X,&Y);bfs(X,Y);return false;}
